import React, { useEffect, useState, useRef } from "react";
import axios from "axios";
import "./PriceList.css";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [priceFilter, setPriceFilter] = useState("all");
  const [selectedItems, setSelectedItems] = useState([]);
  const [selectAll, setSelectAll] = useState(false);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    file: null,
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef();

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  useEffect(() => {
    applyFilters();
  }, [searchTerm, selectedCategory, priceFilter, items]);

  const fetchItems = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API_URL);
      if (res.data.success) {
        setItems(res.data.data);
        setFiltered(res.data.data);
      }
    } catch (err) {
      console.error("Error fetching items:", err);
      alert("Error loading items. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_URL);
      if (res.data.success) setCategories(res.data.categories);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  const applyFilters = () => {
    let temp = [...items];

    if (searchTerm.trim()) {
      temp = temp.filter((i) =>
        i.name.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedCategory !== "all") {
      temp = temp.filter((i) => i.category?._id === selectedCategory);
    }

    if (priceFilter === "positive") temp = temp.filter((i) => i.difference > 0);
    else if (priceFilter === "negative") temp = temp.filter((i) => i.difference < 0);
    else if (priceFilter === "zero") temp = temp.filter((i) => i.difference === 0);

    setFiltered(temp);
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (files) setForm({ ...form, file: files[0] });
    else setForm({ ...form, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (!form.name || !form.category || !form.basePrice) {
        alert("Name, category, and base price are required");
        setLoading(false);
        return;
      }

      const fd = new FormData();
      Object.keys(form).forEach((key) => {
        if (form[key]) fd.append(key, form[key]);
      });

      if (editId) {
        await axios.put(`${API_URL}/${editId}`, fd);
        alert("✅ Price updated successfully!");
      } else {
        await axios.post(API_URL, fd);
        alert("✅ Price added successfully!");
      }

      resetForm();
      fetchItems();
    } catch (err) {
      console.error("Save error:", err);
      alert("❌ Error saving price. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setForm({
      name: "",
      category: "",
      description: "",
      basePrice: "",
      difference: "",
      validTill: "",
      file: null,
    });
    setEditId(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category?._id || "",
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference || "",
      validTill: item.validTill ? item.validTill.split("T")[0] : "",
      file: null,
    });
    setEditId(item._id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("⚠️ Are you sure you want to delete this item?")) return;
    setLoading(true);
    try {
      await axios.delete(`${API_URL}/${id}`);
      alert("✅ Item deleted successfully!");
      fetchItems();
    } catch (err) {
      console.error("Delete error:", err);
      alert("❌ Error deleting item. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleBulkDelete = async () => {
    if (selectedItems.length === 0) return alert("⚠️ No items selected");
    if (!window.confirm(`⚠️ Delete ${selectedItems.length} items?`)) return;
    setLoading(true);
    try {
      await Promise.all(selectedItems.map((id) => axios.delete(`${API_URL}/${id}`)));
      alert("✅ Deleted successfully!");
      setSelectedItems([]);
      setSelectAll(false);
      fetchItems();
    } catch (err) {
      console.error("Bulk delete error:", err);
      alert("❌ Error deleting items. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAll = (checked) => {
    setSelectAll(checked);
    if (checked) setSelectedItems(filtered.map((i) => i._id));
    else setSelectedItems([]);
  };

  const toggleSelectItem = (id) => {
    setSelectedItems((prev) =>
      prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id]
    );
  };

  const calculateFinalPrice = (basePrice, difference) => {
    return basePrice + (difference || 0);
  };

  const formatDate = (date) => {
    if (!date) return "-";
    return new Date(date).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });
  };

  return (
    <div className="price-container">
      {/* Header Section */}
      <div className="header-section">
        <h1>💰 Price Management System</h1>
        <p>Manage, filter, and search product prices efficiently</p>
      </div>

      {/* Search & Filter Bar */}
      <div className="search-filter-bar">
        <div className="search-box">
          <svg className="search-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <circle cx="11" cy="11" r="8"></circle>
            <path d="m21 21-4.35-4.35"></path>
          </svg>
          <input
            type="text"
            placeholder="🔍 Search by product name..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
          <option value="all">📁 All Categories</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>

        <select value={priceFilter} onChange={(e) => setPriceFilter(e.target.value)}>
          <option value="all">💵 All Differences</option>
          <option value="positive">📈 Positive (+)</option>
          <option value="negative">📉 Negative (-)</option>
          <option value="zero">➖ Zero (0)</option>
        </select>

        {selectedItems.length > 0 && (
          <button className="btn delete" onClick={handleBulkDelete}>
            🗑️ Delete Selected ({selectedItems.length})
          </button>
        )}
      </div>

      {/* Form Section */}
      <form className="price-form" onSubmit={handleSubmit}>
        <div className="form-header">
          <h2>{editId ? "✏️ Edit Price" : "➕ Add New Price"}</h2>
        </div>
        
        <input 
          name="name" 
          value={form.name} 
          onChange={handleChange} 
          placeholder="Product Name *" 
          required 
        />
        
        <select name="category" value={form.category} onChange={handleChange} required>
          <option value="">Select Category *</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>
        
        <input 
          type="number" 
          name="basePrice" 
          value={form.basePrice} 
          onChange={handleChange} 
          placeholder="Base Price (₹) *" 
          required 
          min="0"
          step="0.01"
        />
        
        <input 
          type="number" 
          name="difference" 
          value={form.difference} 
          onChange={handleChange} 
          placeholder="Price Difference (₹)" 
          step="0.01"
        />
        
        <input 
          type="date" 
          name="validTill" 
          value={form.validTill} 
          onChange={handleChange}
          min={new Date().toISOString().split('T')[0]}
        />
        
        <input 
          type="file" 
          name="file" 
          onChange={handleChange} 
          accept="image/*"
          ref={fileInputRef}
        />
        
        <textarea 
          name="description" 
          value={form.description} 
          onChange={handleChange} 
          placeholder="Product Description (Optional)..."
          rows="3"
        />
        
        <div className="form-actions">
          <button type="submit" className="btn primary" disabled={loading}>
            {loading ? "⏳ Processing..." : editId ? "✅ Update Price" : "➕ Add Price"}
          </button>
          
          {editId && (
            <button type="button" className="btn secondary" onClick={resetForm}>
              ❌ Cancel Edit
            </button>
          )}
        </div>
      </form>

      {/* Statistics */}
      <div className="stats-section">
        <div className="stat-card">
          <div className="stat-icon">📦</div>
          <div className="stat-info">
            <h3>{filtered.length}</h3>
            <p>Total Items</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📁</div>
          <div className="stat-info">
            <h3>{categories.length}</h3>
            <p>Categories</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-info">
            <h3>{selectedItems.length}</h3>
            <p>Selected</p>
          </div>
        </div>
      </div>

      {/* Table Section */}
      <div className="table-card">
        <div className="table-header">
          <h2>📋 Price List</h2>
          <span className="result-count">{filtered.length} items found</span>
        </div>

        {loading ? (
          <div className="loader">
            <div className="spinner"></div>
            <p>Loading data...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">📭</div>
            <p>No items found. Try adjusting your filters.</p>
          </div>
        ) : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>
                    <input 
                      type="checkbox" 
                      checked={selectAll} 
                      onChange={(e) => toggleSelectAll(e.target.checked)} 
                    />
                  </th>
                  <th>Image</th>
                  <th>Product Name</th>
                  <th>Category</th>
                  <th>Base Price</th>
                  <th>Difference</th>
                  <th>Final Price</th>
                  <th>Valid Till</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((item) => {
                  const finalPrice = calculateFinalPrice(item.basePrice, item.difference);
                  const diffClass = item.difference > 0 ? 'positive' : item.difference < 0 ? 'negative' : 'zero';
                  
                  return (
                    <tr key={item._id}>
                      <td>
                        <input
                          type="checkbox"
                          checked={selectedItems.includes(item._id)}
                          onChange={() => toggleSelectItem(item._id)}
                        />
                      </td>
                      <td>
                        {item.image ? (
                          <img src={item.image} alt={item.name} className="product-image" />
                        ) : (
                          <div className="no-image">🖼️</div>
                        )}
                      </td>
                      <td className="product-name">{item.name}</td>
                      <td>
                        <span className="category-badge">
                          {item.category?.name || "N/A"}
                        </span>
                      </td>
                      <td className="price">₹{item.basePrice.toFixed(2)}</td>
                      <td>
                        <span className={`difference ${diffClass}`}>
                          {item.difference > 0 ? '+' : ''}{item.difference || 0}
                        </span>
                      </td>
                      <td className="price final-price">₹{finalPrice.toFixed(2)}</td>
                      <td className="date">{formatDate(item.validTill)}</td>
                      <td>
                        <div className="action-buttons">
                          <button 
                            className="btn edit" 
                            onClick={() => handleEdit(item)}
                            title="Edit Item"
                          >
                            ✏️ Edit
                          </button>
                          <button 
                            className="btn delete" 
                            onClick={() => handleDelete(item._id)}
                            title="Delete Item"
                          >
                            🗑️ Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
